import Testing

@testable import ADWebBuild

// homepageExtras (buildHomepageExtras) → the index page's design-kind Fonts /
// Symbols entries, byte-exact against renderIndexPage with the extras hook.

private let extrasCfg = SiteConfig(
    baseUrl: "https://x.test", siteName: "Docs", assetVersion: "v1", bundled: true, buildDate: "2026-06-30")
private let extrasFrameworks: [IndexFramework] = [
    IndexFramework(kind: "Frameworks", slug: "swiftui", displayName: "SwiftUI", docCount: 42)
]

@Test func homepageExtrasShape() {
    let extras = BuildSite.homepageExtras(extrasCfg)
    #expect(extras.count == 1)
    #expect(extras[0].kind == "design")
    let items = extras[0].items
    #expect(items.count == 2)
    #expect(items[0].slug == "fonts")
    #expect(items[0].displayName == "Apple Fonts")
    #expect(items[0].href == "https://x.test/fonts")
    #expect(items[1].slug == "symbols")
    #expect(items[1].href == "https://x.test/symbols")
}

